const inp = $input.first().json;
const ctx = inp.context || {};
const emp = ctx.employee || {}, vio = ctx.violation || {}, mgr = ctx.manager || {};
const wp = ctx.workplace || {};
const wit = Array.isArray(ctx.witnesses) ? ctx.witnesses : [];
const w1 = wit[0] || {}, w2 = wit[1] || {};
const U = '[УТОЧНИТЬ]';
function ru(d){ const m = String(d||'').match(/^(\d{4})-(\d{2})-(\d{2})$/); return m ? `${m[3]}.${m[2]}.${m[1]}` : (d || U); }
const scenario = ctx.scenario || 'progul_ochny';
// какие документы нужны для сценария (расширяемо под новые проекты)
const DOC_MAP = {
  progul_ochny: { нужен_акт: true,  нужна_сз: true },
  zaglushka:    { нужен_акт: false, нужна_сз: true },
};
const docs = DOC_MAP[scenario] || { нужен_акт: true, нужна_сз: true };
const t = new Date();
const dd = String(t.getDate()).padStart(2,'0'), mm = String(t.getMonth()+1).padStart(2,'0'), yyyy = t.getFullYear();
const hh = String(t.getHours()).padStart(2,'0'), mi = String(t.getMinutes()).padStart(2,'0');
return [{ json: {
  нужен_акт: docs.нужен_акт,
  нужна_сз: docs.нужна_сз,
  акт_file_id: '1pz4mHqz6dleQKZvit3VRfXs_h95VWqKl',
  сз_file_id: '1iiqEDumDy61qRr9lv0kFGpkUB3hTpkWd',
  chat_id: inp.chat_id,
  // --- сырые поля для промпта Ollama (чтобы не было far-reference) ---
  contactAttempts: ctx.contactAttempts || '',
  respectableReason: !!ctx.respectableReason,
  respectableReasonComment: ctx.respectableReasonComment || '',
  evidenceDescription: ctx.evidenceDescription || '',
  // --- плейсхолдеры шаблонов (25) ---
  организация: 'АО «ПФ «СКБ Контур»',
  город: wp.city || U,
  адрес: wp.address || U,
  время_составления: `${hh}:${mi}`,
  дата_составления: `${dd}.${mm}.${yyyy}`,
  год: String(yyyy),
  дата_отсутствия: ru(vio.date),
  время_начала: vio.absenceStart || U,
  время_окончания: vio.absenceEnd || U,
  подразделение: emp.department || U,
  должность_работника: emp.position || U,
  фио_работника: emp.name || U,
  должность_составителя: mgr.position || U,
  фио_составителя: mgr.name || U,
  свидетель_1_фио: w1.name || U,
  свидетель_1_должность: w1.position || U,
  свидетель_2_фио: w2.name || U,
  свидетель_2_должность: w2.position || U,
  должность_руководителя_организации: 'Директору',
  фио_руководителя_организации: '',
  должность_автора: mgr.position || U,
  подразделение_автора: mgr.department || U,
  фио_автора: mgr.name || U,
} }];

