const base = $('Значения документов').first().json;
let smart = {};
try {
  const resp = $input.first().json.response || '{}';
  const m = resp.match(/\{[\s\S]*\}/);
  smart = JSON.parse(m ? m[0] : resp);
} catch (e) { smart = {}; }
return [{ json: {
  ...base,
  фио_работника_род: smart['фио_работника_род'] || base['фио_работника'],
  обстоятельства: smart['обстоятельства'] || '[УТОЧНИТЬ]',
  приложения: smart['приложения'] || 'Отсутствуют',
} }];

const AdmZip = require('adm-zip');
const v = $('Объединить значения').first().json;
const SKIP = new Set(['chat_id']);
const inBin = $input.item.binary.data;
const fileName = (inBin && inBin.fileName) || 'Документ.docx';
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const zip = new AdmZip(buffer);
let xml = zip.readAsText('word/document.xml');
for (const [key, val] of Object.entries(v)) {
  if (SKIP.has(key) || key.endsWith('_file_id')) continue;
  xml = xml.split('{{' + key + '}}').join(String(val ?? ''));
}
zip.updateFile('word/document.xml', Buffer.from(xml, 'utf8'));
const out = zip.toBuffer();
const binary = await this.helpers.prepareBinaryData(out, fileName, 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
return [{ json: { rendered: fileName }, binary: { data: binary } }];

