const d = $input.first().json;
const ctx = d.context;
const prompt = `Ты — юридический ассистент по трудовому праву. Твоя задача — кратко и точно сформулировать нарушение трудовых обязанностей со ссылками на нормативные акты.

## Данные о нарушении
Сотрудник: ${ctx.employee?.name || '[не указано]'}
Должность: ${ctx.employee?.position || '[не указано]'}
Подразделение: ${ctx.employee?.department || '[не указано]'}
Дата нарушения: ${ctx.violation?.date || '[не указано]'}
Описание: ${ctx.violation?.description || 'Прогул — отсутствие на рабочем месте без уважительной причины'}
Уважительная причина: ${ctx.respectableReason ? 'Есть: ' + ctx.respectableReasonComment : 'Отсутствует'}

## Чеклист (внутренняя инструкция)
${d.checklist_content}

## Задача
Сформулируй нарушение в 2-4 предложениях для включения в служебную записку. Укажи конкретные статьи, пункты. Формат: юридически грамотно, сухо, без лишних слов.
Отвечай ТОЛЬКО формулировкой нарушения, без вводных фраз.`;
return [{ json: { ...d, prompt_rag: prompt } }];

const r = $input.first().json;
const violations = r.response?.trim() || '[Не удалось сформулировать нарушение]';
const prev = $('Vision: анализ доказательств (заглушка)1').first().json;
return [{ json: {
  context: prev.context,
  chat_id: prev.chat_id,
  dates: prev.dates,
  checklist_content: prev.checklist_content,
  vision_analysis: prev.vision_analysis,
  violations
} }];

const out = '✅ Готово! Акт об отсутствии и служебная записка сформированы и отправлены файлами выше.\n\n'
  + '⚠️ Проверьте документы и заполните поля [УТОЧНИТЬ] (свидетели, адрес, руководитель организации) перед подписанием.\n'
  + 'Передайте готовый пакет Черепановой Т. или Касмыниной О.';
return [{ json: { output: out } }];

// Чеклист подгружается ДИНАМИЧЕСКИ из Google Drive (нода «Drive: скачать чеклист»).
// Источник правды: knowledge/progul_checklist.md → выгружен в Google Drive
// (fileId 1AkZ9oCM6EzNHewmEiwqvERmq9cKDMt0V). Команда правит чеклист прямо в Drive.
// Сроки ст.193 здесь НЕ дублируются — они проверяются в main-агенте (calc_deadlines).
const AdmZip = require('adm-zip');
let checklist = '[чеклист не загружен из Drive]';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length) {
    // Google Doc export=text/plain → обычный текст; .docx → zip (PK..) → достаём из word/document.xml
    if (buf[0] === 0x50 && buf[1] === 0x4B) {
      const zip = new AdmZip(buf);
      const xml = zip.readAsText('word/document.xml');
      checklist = xml.replace(/<\/w:p>/g, '\n').replace(/<[^>]+>/g, '').replace(/[ \t]+/g, ' ').trim();
    } else {
      checklist = buf.toString('utf8').replace(/^\uFEFF/, '').trim();
    }
  }
} catch (e) {
  checklist = '[ошибка загрузки чеклиста из Drive: ' + e.message + ']';
}

const d = $('Нормализовать данные').first().json;
return [{ json: { ...d, checklist_content: checklist } }];

const raw = $input.first().json;
let data = raw;
if (raw.query && typeof raw.query === 'object' && !Array.isArray(raw.query)) {
  data = raw.query;
} else if (typeof raw.input === 'string') {
  try { data = JSON.parse(raw.input); } catch(e) {}
} else if (typeof raw.query === 'string') {
  try { data = JSON.parse(raw.query); } catch(e) {}
}
if (!data.employee) throw new Error('hr_generate: не переданы данные employee. Получено: ' + JSON.stringify(raw));
if (!data.violation) throw new Error('hr_generate: не переданы данные violation.');
data.scenario = data.scenario || 'progul_ochny';
return [{ json: {
  context: data,
  chat_id: data.chat_id || raw.chat_id || null,
  evidence: data.evidence || raw.evidence || null,
  violationDate: data.violation.date,
  discoveryDate: data.violation.discoveryDate
} }];
